      },
      {
        "name": "Projection Updater (Synchronizer)",
        "responsibility": "Listens for domain events (or polls a change log) from the write side and updates the denormalized read projections. Handles idempotent replay and projection rebuilds.",
        "boundaries": "Unidirectional data flow: write model → projections. No write-back path. Runs asynchronously but with low latency given the ~500 events/day volume."
      },
      {
        "name": "Operations Dashboard API",
        "responsibility": "Thin query layer that reads directly from the denormalized projections. Simple SELECT queries, no joins. Supports filtering, pagination, and time-range scoping.",
        "boundaries": "Read-only access to projection tables. Cannot issue commands. Returns pre-aggregated data."
      }
    ],
    "interfaces": [
      {
        "from": "Order Service (Commands)",
        "to": "Write Model",
        "contract": "CreateOrder, UpdateOrderStatus, AssignCourier, RecordDelivery — standard transactional writes against normalized schema",
        "coupling_type": "direct (same database, same process)"
      },
      {
        "from": "Write Model",
        "to": "Projection Updater",
        "contract": "Domain events: OrderCreated, OrderStatusChanged, DeliveryCompleted, CourierAssigned — published via an outbox table or change-data-capture",
        "coupling_type": "loose (event-driven, asynchronous)"
      },
      {
        "from": "Projection Updater",
        "to": "Read Model",
        "contract": "Upserts into denormalized projection tables: orders_by_status_summary, delivery_success_projection, transit_time_zone_projection, courier_performance_projection",
        "coupling_type": "direct (same database, write access to projection tables)"
      },
      {
        "from": "Operations Dashboard API",
        "to": "Read Model",
        "contract": "Simple SELECT queries against flat projection tables. No joins. Parameterized by date range, zone, status, courier_id.",
        "coupling_type": "direct (same database, read-only)"
      }
