      },
      {
        "name": "Operations Reporting (Read)",
        "classification": "supporting",
        "aggregates": [
          "OrderStatusSummary (pre-aggregated counts by status, date, zone)",
          "DeliverySuccessProjection (success/failure rates by zone, time period)",
          "TransitTimeProjection (average transit time by zone, date range)",
          "CourierPerformanceProjection (delivery count, success rate, avg time per courier)"
