    "context_map": [
      {
        "upstream": "Order Management (Write)",
        "downstream": "Operations Reporting (Read)",
        "relationship": "Published Language — Write context publishes domain events in a stable schema. Read context consumes and projects them. The read side conforms to the write side's event contracts but owns its own projection schema."
