    {
      "decision": "Denormalized projection tables instead of materialized views",
      "gains": "Full control over update timing and schema. Can include pre-aggregated data (counts, averages). Projection rebuild is explicit and testable. No hidden refresh costs.",
      "sacrifices": "Requires custom Projection Updater code. More moving parts than a simple materialized view.",
      "alternatives_considered": [
        "Database materialized views — simpler to implement but refresh is all-or-nothing on 50M rows, hard to make incremental, and opaque in failure modes",
        "Application-level caching (Redis) — solves latency but adds cache invalidation complexity and a new infrastructure dependency; doesn't solve the underlying query cost"
      ]
    },
    {
      "decision": "Transactional outbox over direct event publishing",
      "gains": "Atomic event capture — no event is lost if the message broker is down. No dual-write problem. At 500 events/day, outbox polling is near-zero cost.",
      "sacrifices": "Slightly more complex than a simple post-commit hook. Requires a poller or CDC mechanism.",
      "alternatives_considered": [
        "Direct publish after commit — simpler but risks lost events if the publish fails after DB commit",
        "CDC (Change Data Capture) on the write tables — viable alternative; Debezium or similar could replace the outbox, but adds infrastructure dependency"
      ]
